/**
 * Operations processor for advanced URL pattern transformations
 * Supports: array, lowercase, uppercase, capitalize, map, regex, default operations
 */
export interface AdvancedConfig {
    fields: {
        [fieldPath: string]: {
            operations: Operation[];
        };
    };
}
export interface Operation {
    type: 'array' | 'lowercase' | 'uppercase' | 'capitalize' | 'map' | 'regex' | 'default';
    config?: OperationConfig;
}
export type OperationConfig = ArrayConfig | MapConfig | RegexConfig | DefaultConfig;
export interface ArrayConfig {
    pick?: 'all' | 'first' | 'last';
    joinWith?: string;
}
export interface MapConfig {
    [key: string]: string;
}
export interface RegexConfig {
    pattern: string;
    replace: string;
}
export interface DefaultConfig {
    value: any;
}
/**
 * Parse advanced_config JSON string safely
 */
export declare function parseAdvancedConfig(advancedConfigJson?: string): AdvancedConfig | null;
/**
 * Apply array operation to a value
 */
export declare function applyArrayOperation(value: any, config?: ArrayConfig): string;
/**
 * Apply lowercase operation
 */
export declare function applyLowercaseOperation(value: any): string;
/**
 * Apply uppercase operation
 */
export declare function applyUppercaseOperation(value: any): string;
/**
 * Apply capitalize operation (first letter uppercase)
 */
export declare function applyCapitalizeOperation(value: any): string;
/**
 * Apply map operation (value mapping)
 */
export declare function applyMapOperation(value: any, config?: MapConfig): string;
/**
 * Apply regex operation (pattern matching and replacement)
 */
export declare function applyRegexOperation(value: any, config?: RegexConfig): string;
/**
 * Apply default operation (fallback value)
 */
export declare function applyDefaultOperation(value: any, config?: DefaultConfig): any;
/**
 * Apply operations pipeline to a value
 * Operations are applied in sequence
 */
export declare function applyOperations(value: any, operations: Operation[] | undefined, context?: Record<string, any>): string;
